/* Represents a chunk of records in a file, defining the file descriptor, starting and ending block IDs, and the counts of records and blocks in the chunk. Useful for managing and sorting records within specific chunks. */
typedef struct {
    int file_desc;
    int from_BlockId;
    int to_BlockId;
    int recordsInChunk;
    int blocksInChunk;
} CHUNK;

/* Represents an iterator for traversing chunks within a file, storing the file descriptor, current block, last block ID, and the total number of blocks in each chunk. Useful for efficiently iterating over file chunks.*/
typedef struct {
    int file_desc;
    int current;
    int lastBlocksID;
    int blocksInChunk;
} CHUNK_Iterator;

/* Iterates through records in a CHUNK, encapsulating the id of the current block and a cursor in that block. */
typedef struct CHUNK_RecordIterator {
    CHUNK chunk;
    int currentBlockId;
    int cursor;
} CHUNK_RecordIterator;

#include <merge.h>
#include <stdio.h>
#include "chunk.h"


CHUNK_Iterator CHUNK_CreateIterator(int fileDesc, int blocksInChunk) {
    CHUNK_Iterator iterator;

    iterator.file_desc = fileDesc;
    iterator.current = 1;  // Initialize the iterator to point to the first block.
    iterator.lastBlocksID = HP_GetIdOfLastBlock(fileDesc);  // Get the last block ID in the file.
    iterator.blocksInChunk = blocksInChunk;

    return iterator;
}

int CHUNK_GetNext(CHUNK_Iterator *iterator, CHUNK *chunk) {
    // Calculate the last block ID to consider in this iteration
    int lastBlockToConsider = iterator->current + iterator->blocksInChunk - 1;

    // Check if there are more blocks to iterate over
    if (iterator->current <= iterator->lastBlocksID) {
        chunk->file_desc = iterator->file_desc;
        chunk->from_BlockId = iterator->current;

        // Ensure that to_BlockId does not exceed the last block ID
        chunk->to_BlockId = (lastBlockToConsider <= iterator->lastBlocksID) ? lastBlockToConsider : iterator->lastBlocksID;

        // Calculate the number of records and blocks in the chunk
        chunk->recordsInChunk = 0;
        for (int blockId = chunk->from_BlockId; blockId <= chunk->to_BlockId; ++blockId) {
            chunk->recordsInChunk += HP_GetRecordCounter(iterator->file_desc, blockId);
        }

        // Calculate blocksInChunk based on from_BlockId and to_BlockId
        chunk->blocksInChunk = chunk->to_BlockId - chunk->from_BlockId + 1;

        // Update iterator state for the next iteration
        iterator->current = chunk->to_BlockId + 1;

        return 1; // Success
    } else {
        // No more blocks to iterate
        return 0;
    }
}

int CHUNK_GetIthRecordInChunk(CHUNK *chunk, int i, Record *record) {
    // Check if i is a valid index within the recordsInChunk range
    if (i >= 0 && i < chunk->recordsInChunk) {
        // Calculate the block and cursor position for the i-th record
        int blockId = chunk->from_BlockId + (i / HP_GetMaxRecordsInBlock(chunk->file_desc));
        int cursor = i % HP_GetMaxRecordsInBlock(chunk->file_desc);

        // Retrieve the record from the heap file
        if (HP_GetRecord(chunk->file_desc, blockId, cursor, record) == -1) {
            // Record retrieval failed
            HP_Unpin(chunk->file_desc, blockId);
            return -1;
        }

        // Unpin the block after using the record
        HP_Unpin(chunk->file_desc, blockId);

        // Record retrieval successful
        return 0;
    } else {
        // Invalid index
        return -1;
    }
}


int CHUNK_UpdateIthRecord(CHUNK *chunk, int i, Record record) {
    // Check if i is a valid index within the recordsInChunk range
    if (i >= 0 && i < chunk->recordsInChunk) {
        // Calculate the block and cursor position for the i-th record
        int blockId = chunk->from_BlockId + (i / HP_GetMaxRecordsInBlock(chunk->file_desc));
        int cursor = i % HP_GetMaxRecordsInBlock(chunk->file_desc);

        // Update the record in the heap file
        if (HP_UpdateRecord(chunk->file_desc, blockId, cursor, record) == -1) {
            // Record update failed
            HP_Unpin(chunk->file_desc, blockId);
            return -1;
