        // Unpin the block after updating the record
        HP_Unpin(chunk->file_desc, blockId);

        // Record update successful
        return 0;
    } else {
        // Invalid index
        return -1;
    }
}

void CHUNK_Print(CHUNK chunk) {
    printf("Printing records in CHUNK:\n");

    // Iterate through records in the chunk
    for (int i = 0; i < chunk.recordsInChunk; ++i) {
        Record record;

        // Retrieve the i-th record in the chunk
        if (CHUNK_GetIthRecordInChunk(&chunk, i, &record) == 0) {
