            printRecord(record);
        } else {
            // Handle record retrieval failure
            printf("Failed to retrieve record %d in the chunk.\n", i + 1);
        }
    }
}

CHUNK_RecordIterator CHUNK_CreateRecordIterator(CHUNK *chunk) {
    CHUNK_RecordIterator iterator;

    // Check if the chunk pointer is NULL
    if (chunk == NULL) {
        // Handle the case of a NULL pointer (e.g., log an error, return a default iterator, etc.)
        // For simplicity, let's set the iterator properties to default values
        iterator.chunk.file_desc = -1;
        iterator.chunk.from_BlockId = -1;
        iterator.chunk.to_BlockId = -1;
        iterator.chunk.recordsInChunk = 0;
        iterator.chunk.blocksInChunk = 0;
        iterator.currentBlockId = -1;
        iterator.cursor = -1;
        return iterator;
    }

    // Initialize iterator properties
    iterator.chunk = *chunk; // Copy the CHUNK structure
    iterator.currentBlockId = chunk->from_BlockId;
    iterator.cursor = 0;

    return iterator;
}

int CHUNK_GetNextRecord(CHUNK_RecordIterator *iterator, Record *record) {
    // Check if the iterator is valid
    if (iterator == NULL || iterator->chunk.file_desc == -1 || iterator->cursor < 0) {
        // Invalid iterator, return an error code (you can customize error handling as needed)
        return -1;
    }

    while (1) {
        // Check if there are more records in the current block
        int recordsInBlock = HP_GetRecordCounter(iterator->chunk.file_desc, iterator->currentBlockId);
        if (iterator->cursor < recordsInBlock) {
            // Retrieve the record from the current block
            if (HP_GetRecord(iterator->chunk.file_desc, iterator->currentBlockId, iterator->cursor, record) == 0) {
                // Move the cursor to the next record in the current block
                iterator->cursor++;
                HP_Unpin(iterator->chunk.file_desc, iterator->currentBlockId); // Unpin the block
                return 0; // Successful record retrieval
            } else {
                // Record retrieval failed
                HP_Unpin(iterator->chunk.file_desc, iterator->currentBlockId); // Unpin the block on failure
                return -1;
            }
        } else {
            // Move to the next block if available
            if (iterator->currentBlockId < iterator->chunk.to_BlockId) {
                iterator->currentBlockId++;
                iterator->cursor = 0; // Reset the cursor for the new block
            } else {
                // No more records in the chunk
                return -1;
            }
        }
    }
}

